- Use `nest new nest-crud-app` to create a new NestJS project.
- Install dependencies with `npm install @nestjs/typeorm typeorm pg`.
- Configure TypeORM in `app.module.ts`:
  ```typescript
  import { Module } from '@nestjs/common';
  import { TypeOrmModule } from '@nestjs/typeorm';

  @Module({
    imports: [
      TypeOrmModule.forRoot({
        type: 'postgres',
        host: 'localhost',
        port: 5432,
        username: 'your_username',
        password: 'your_password',
        database: 'your_database',
        entities: [__dirname + '/**/*.entity{.ts,.js}'],
        synchronize: true, // Use caution with production
      }),
    ],
  })
  export class AppModule {}
  ```
- Create an entity using `nest generate entity User`.
- Inject the repository in a service:
  ```typescript
  import { Injectable } from '@nestjs/common';
  import { InjectRepository } from '@nestjs/typeorm';
  import { Repository } from 'typeorm';
  import { User } from './user.entity';

  @Injectable()
  export class UsersService {
    constructor(
      @InjectRepository(User)
      private usersRepository: Repository<User>,
    ) {}

    findAll(): Promise<User[]> {
      return this.usersRepository.find();
    }

    findOne(id: number): Promise<User> {
      return this.usersRepository.findOne(id);
    }

    async remove(id: number): Promise<void> {
      await this.usersRepository.delete(id);
    }
  }
  ```
- Use the service in a controller:
  ```typescript
  import { Controller, Get, Param } from '@nestjs/common';
  import { UsersService } from './users.service';

  @Controller('users')
  export class UsersController {
    constructor(private readonly usersService: UsersService) {}

    @Get()
    findAll() {
      return this.usersService.findAll();
    }

    @Get(':id')
    findOne(@Param('id') id: string) {
      return this.usersService.findOne(+id);
    }
  }
  ```
- Ensure PostgreSQL is running and accessible.
- Adjust `synchronize` to `false` in production for safety.
